(function () {
  'use strict';

  var APP_ID   = window.edrone_app_id   || '';
  var STORE_ID = window.edrone_store_id || '';
  var DEBUG    = window.edrone_debug    || false;

  if (!STORE_ID) {
    try {
      var cachedStoreId = sessionStorage.getItem('edrone_store_id');
      if (cachedStoreId) {
        STORE_ID = cachedStoreId;
        log('Config | store_id do sessionStorage', { store_id: STORE_ID });
      }
    } catch (e) {}
  }

  if (!STORE_ID) {
    try {
      var nuxtState = window.__NUXT__ || window.__nuxt_state__;
      if (nuxtState) {
        if (nuxtState.state && nuxtState.state.store && nuxtState.state.store.id) {
          STORE_ID = nuxtState.state.store.id;
          log('Config | store_id extraído do __NUXT__.state.store.id', { store_id: STORE_ID });
        }
        if (!STORE_ID) {
          var nuxtStr = JSON.stringify(nuxtState);
          var match   = nuxtStr.match(/"store[_-]?id"\s*:\s*"([a-f0-9]{32})"/i);
          if (match) {
            STORE_ID = match[1];
            log('Config | store_id extraído via regex do __NUXT__', { store_id: STORE_ID });
          }
        }
      }
    } catch (e) {}
  }

  if (STORE_ID) {
    try { sessionStorage.setItem('edrone_store_id', STORE_ID); } catch (e) {}
  }

  if (!APP_ID) {
    console.warn('[edrone-loader] window.edrone_app_id não definido. Abortando.');
    return;
  }

  function log(label, data) {
    if (!DEBUG) return;
    console.groupCollapsed('%c[Edrone] ' + label, 'color:#7B2FBE;font-weight:bold;');
    console.log(data);
    console.groupEnd();
  }

  var _sdkReady = false;
  var _loaderReady = false;
  var _pendingInit = null;

  function loadSDK() {
    window._edrone          = window._edrone || {};
    _edrone.app_id          = APP_ID;
    _edrone.version         = '1.0.0';
    _edrone.platform_version = '1.0.0';
    _edrone.platform        = 'convertr';

    var path = window.location.pathname.replace(/\/$/, '');
    var isProductPage   = !!path.match(/\/p$/);
    var isCategoryPage  = !!path.match(/\/c$/);
    var isCheckoutPage  = path.indexOf('/checkout') !== -1;

    if (isProductPage || isCategoryPage || isCheckoutPage) {
      var _savedInit = _edrone.init || null;
      _edrone.init = function () {
        if (_loaderReady) {
          log('SDK | init liberado', { action_type: this.action_type });
          _sdkReady = true;
          if (_savedInit) {
            _edrone.init = _savedInit;
            _edrone.__originalInit = _savedInit;
            return _savedInit.apply(_edrone, arguments);
          }
        } else {
          log('SDK | init bloqueado (loader não pronto)', { action_type: this.action_type });
          _pendingInit = true;
          return;
        }
      };
    }

    var s   = document.createElement('script');
    s.type  = 'text/javascript';
    s.async = true;
    s.src   = ('https:' === document.location.protocol ? 'https:' : 'http:') +
              '//d3bo67muzbfgtl.cloudfront.net/edrone_2_0.js?app_id=' + APP_ID;

    s.onload = function () {
      _sdkReady = true;
      if (window._edrone && typeof _edrone.init === 'function' && !_edrone.__originalInit) {
        _edrone.__originalInit = _edrone.init;
      }
      log('SDK | script carregado', {});
    };

    var first = document.getElementsByTagName('script')[0];
    first.parentNode.insertBefore(s, first);
    log('SDK | iniciando carregamento', { app_id: APP_ID });
  }

  function setLoaderReady() {
    _loaderReady = true;
    if (window._edrone) {
      if (_edrone.__originalInit) {
        _edrone.init = _edrone.__originalInit;
      } else {
        try { delete _edrone.init; } catch(e) {}
      }
    }
    log('SDK | loader pronto, init restaurado', {});
  }

  function dispatch(payload) {
    window._edrone = window._edrone || {};
    Object.keys(payload).forEach(function (k) { _edrone[k] = payload[k]; });
    _edrone.init();
    log('Payload enviado', payload);
  }

  function resolveCategoria(item_category) {
    if (item_category && item_category.trim()) {
      return {
        id:   item_category.trim().toLowerCase().replace(/[^\w ]+/g, '').replace(/ +/g, '-'),
        name: item_category.trim()
      };
    }
    var ref      = document.referrer || '';
    var refClean = ref.split('?')[0].replace(/\/$/, '');
    if (refClean.match(/\/c$/)) {
      var segments    = refClean.replace(/\/c$/, '').split('/');
      var lastSegment = (segments[segments.length - 1] || '').replace(/-\d+$/, '');
      if (lastSegment) {
        return {
          id:   lastSegment,
          name: lastSegment.replace(/-/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); })
        };
      }
    }
    return { id: 'home', name: 'Home' };
  }

  function lsGet(key) {
    try { return JSON.parse(localStorage.getItem(key)); } catch (e) { return null; }
  }
  function lsSet(key, val) {
    try { localStorage.setItem(key, JSON.stringify(val)); } catch (e) {}
  }
  function lsRemove(key) {
    try { localStorage.removeItem(key); } catch (e) {}
  }

  function resolveProductCategories(productId, callback) {
    if (!STORE_ID || !productId) {
      log('resolveProductCategories | ⚠️ sem STORE_ID ou productId', {});
      return callback('home', 'Home');
    }

    fetch('/api/catalog/products/' + productId, {
      headers: { 'store-id': STORE_ID, 'accept': 'application/json' }
    })
      .then(function (r) { return r.json(); })
      .then(function (apiData) {
        var productCatIds = (!apiData.error && apiData.data && apiData.data.category_ids)
          ? apiData.data.category_ids : [];

        if (!productCatIds.length) {
          log('resolveProductCategories | Produto sem category_ids', { productId: productId });
          return callback('home', 'Home');
        }

        getCategoryMap(function (map) {
          var ids   = [];
          var names = [];

          productCatIds.forEach(function (cid) {
            if (map[cid]) {
              var path = buildCategoryPath(cid, map);
              path.ids.split('~').forEach(function (id) {
                if (ids.indexOf(id) === -1) ids.push(id);
              });
              path.names.split('~').forEach(function (name) {
                if (names.indexOf(name) === -1) names.push(name);
              });
            }
          });

          if (ids.length) {
            log('resolveProductCategories | Resolvido', { ids: ids });
            callback(ids.join('~'), names.join('~'));
          } else {
            log('resolveProductCategories | Nenhum match no mapa, fallback home', {});
            callback('home', 'Home');
          }
        });
      })
      .catch(function (err) {
        log('resolveProductCategories | ⚠️ API falhou', { error: err.message });
        callback('home', 'Home');
      });
  }

  function handleAddToCart(data) {
    if (!data || !data.items || !data.items.length) {
      log('Add to Cart | ⚠️ ABORTADO — items ausentes', data);
      return;
    }

    var product   = data.items[0];
    var productId = product.item_id ? product.item_id.toString() : '';

    var raw = {
      product_id:     productId,
      product_sku:    product.item_sku  || '',
      product_title:  (product.item_name || '').trim(),
      product_image:  (product.image_url || '').split('?')[0],
      product_url:    product.permalink || window.location.href.split('?')[0],
      category_ids:   '',
      category_names: ''
    };

    var stored = lsGet('edrone_products') || [];
    var cached = stored.filter(function (p) { return p.product_id == productId; })[0];
    if (cached && cached.category_ids) {
      raw.category_ids   = cached.category_ids;
      raw.category_names = cached.category_names || '';
      log('Add to Cart | Categorias do localStorage', { ids: raw.category_ids });
    }

    function fireAddToCart() {
      dispatch({
        action_type:            'add_to_cart',
        product_ids:            raw.product_id,
        product_skus:           raw.product_sku,
        product_titles:         encodeURIComponent(raw.product_title),
        product_images:         encodeURIComponent(raw.product_image),
        product_urls:           encodeURIComponent(raw.product_url),
        product_category_ids:   raw.category_ids,
        product_category_names: encodeURIComponent(raw.category_names)
      });

      var updatedStored = lsGet('edrone_products') || [];
      if (!updatedStored.some(function (p) { return p.product_id == productId; })) {
        updatedStored.push(raw);
        lsSet('edrone_products', updatedStored);
        log('Add to Cart | Produto salvo no localStorage', raw);
      }
    }

    resolveProductCategories(productId, function (ids, names) {
      raw.category_ids   = ids;
      raw.category_names = names;
      fireAddToCart();
    });
  }

  function handleProductView(data) {
    if (!data || !data.items || !data.items.length) {
      log('Product View | ⚠️ ABORTADO — items ausentes', data);
      return;
    }

    var item      = data.items[0];
    var productId = item.item_id ? item.item_id.toString() : '';

    if (!productId) {
      log('Product View | ⚠️ ABORTADO — product_id não encontrado', {});
      return;
    }

    var productSku   = item.item_sku   || '';
    var productName  = (item.item_name || '').trim();
    var productImage = (item.image_url || '').split('?')[0];
    var productUrl   = item.permalink  || window.location.href.split('?')[0];

    log('Product View | Dados do dataLayer', { id: productId, name: productName });

    function fireWithCategories(catIds, catNames) {
      log('Product View | Disparando', { id: productId, catIds: catIds, catNames: catNames });
      dispatch({
        action_type:            'product_view',
        product_ids:            productId,
        product_skus:           productSku,
        product_titles:         encodeURIComponent(productName),
        product_images:         encodeURIComponent(productImage),
        product_urls:           encodeURIComponent(productUrl),
        product_category_ids:   catIds,
        product_category_names: encodeURIComponent(catNames),
        product_availability:   1
      });

      var stored = lsGet('edrone_products') || [];
      if (!stored.some(function (s) { return s.product_id == productId; })) {
        stored.push({
          product_id:     productId,
          product_sku:    productSku,
          product_url:    productUrl,
          product_image:  productImage,
          category_ids:   catIds,
          category_names: catNames
        });
        lsSet('edrone_products', stored);
      }
    }

    resolveProductCategories(productId, fireWithCategories);
  }

  var _orderFired = {};

  function handleOrder(data) {
    if (!data || !data.transaction_id) {
      log('Order | ⚠️ ABORTADO — transaction_id ausente', data);
      return;
    }

    if (_orderFired[data.transaction_id]) {
      log('Order | ⚠️ ABORTADO — pedido já disparado', { order_id: data.transaction_id });
      return;
    }
    _orderFired[data.transaction_id] = true;

    var stored = lsGet('edrone_products') || [];
    var city   = lsGet('edrone_city')     || '';

    var email = '', firstName = '', lastName = '', phone = '', userId = '';

    if (data.customer) {
      email     = data.customer.email      || '';
      firstName = data.customer.first_name || '';
      lastName  = data.customer.last_name  || '';
      phone     = (data.customer.phone     || '').replace(/\D/g, '');
      userId    = data.customer.taxvat     || data.customer.id || '';
      if (!city) city = data.customer.city || '';
    }

    if (!city && data.shipping_infos) {
      city = data.shipping_infos.delivery_city || data.shipping_infos.delivery_region || '';
    }
    if (!city && data.shipping) {
      city = data.shipping.delivery_city || data.shipping.delivery_region || '';
    }

    var items = data.items || [];

    var resolved = [];
    var pending  = items.length;

    if (!pending) {
      log('Order | ⚠️ ABORTADO — sem itens', {});
      return;
    }

    function fireOrder() {
      var payload = {
        action_type:            'order',
        email:                  email,
        first_name:             firstName,
        last_name:              encodeURIComponent(lastName),
        user_id:                userId,
        subscriber_status:      '1',
        phone:                  phone,
        order_id:               data.transaction_id,
        base_payment_value:     data.value,
        order_payment_value:    data.value,
        base_currency:          'BRL',
        order_currency:         'BRL',
        country:                'BRA',
        city:                   encodeURIComponent(city),
        product_ids:            resolved.map(function(p){ return p.id; }).join('|'),
        product_skus:           resolved.map(function(p){ return p.sku; }).join('|'),
        product_titles:         resolved.map(function(p){ return encodeURIComponent(p.title); }).join('|'),
        product_images:         resolved.map(function(p){ return encodeURIComponent(p.image); }).join('|'),
        product_urls:           resolved.map(function(p){ return encodeURIComponent(p.url); }).join('|'),
        product_counts:         resolved.map(function(p){ return p.count; }).join('|'),
        product_category_ids:   resolved.map(function(p){ return p.catIds; }).join('|'),
        product_category_names: resolved.map(function(p){ return encodeURIComponent(p.catNames); }).join('|')
      };

      setLoaderReady();

      window._edrone = window._edrone || {};
      Object.keys(payload).forEach(function(k) { _edrone[k] = payload[k]; });

      if (typeof _edrone.init === 'function') {
        _edrone.init();
      } else {
        log('Order | ⚠️ _edrone.init não disponível após setLoaderReady', {});
      }

      log('Order | Disparado', { order_id: data.transaction_id });
      lsRemove('edrone_city');
      lsRemove('edrone_products');
      log('Order | localStorage limpo', {});
    }

    items.forEach(function (product, index) {
      var productId = product.product_id ? product.product_id.toString()
                    : product.item_id    ? product.item_id.toString() : '';
      var sku       = product.item_sku || '';
      var title     = (product.item_name || '').trim();
      var count     = parseInt(product.quantity) || 1;
      var img       = (product.image_url || '').split('?')[0];
      var url       = product.permalink || '';

      var cached = stored.filter(function (s) {
        return s.product_id == productId || s.product_id == product.item_id;
      })[0];
      if (cached && !img) img = cached.product_image || '';

      resolveProductCategories(productId, function (catIds, catNames) {
        if (!img && STORE_ID) {
          fetch('/api/catalog/products/' + productId, {
            headers: { 'store-id': STORE_ID, 'accept': 'application/json' }
          })
            .then(function (r) { return r.json(); })
            .then(function (apiData) {
              if (!apiData.error && apiData.data) {
                img = (apiData.data.small_image || apiData.data.thumbnail || '').split('?')[0];
              }
            })
            .catch(function () {})
            .finally(function () {
              resolved[index] = { id: productId, sku: sku, title: title, count: count,
                                  image: img, url: url, catIds: catIds, catNames: catNames };
              if (--pending === 0) fireOrder();
            });
        } else {
          resolved[index] = { id: productId, sku: sku, title: title, count: count,
                              image: img, url: url, catIds: catIds, catNames: catNames };
          if (--pending === 0) fireOrder();
        }
      });
    });
  }

  function handleCategoryView(data) {
    if (!data) {
      log('Category View | ⚠️ ABORTADO — data ausente', data);
      return;
    }

    var catId   = '';
    var catName = '';

    if (Array.isArray(data.category) && data.category.length) {
      var last = data.category[data.category.length - 1];
      catId   = last.id   ? last.id.toString()  : '';
      catName = last.name ? last.name.toString() : '';
    } else {
      var cat = data.category || data;
      catId   = cat.id   ? cat.id.toString()  : '';
      catName = cat.name ? cat.name.toString() : '';
    }

    if (!catId && !catName) {
      log('Category View | ⚠️ ABORTADO — id e name ausentes', data);
      return;
    }

    log('Category View | Passando para waitForSDKAndFire', { id: catId, name: catName });

    waitForSDKAndFire(catId, catName);
  }

  function interceptDataLayer() {
    window.dataLayer = window.dataLayer || [];

    var _originalPush = window.dataLayer.push.bind(window.dataLayer);

    window.dataLayer.push = function () {
      var result = _originalPush.apply(window.dataLayer, arguments);

      Array.prototype.forEach.call(arguments, function (item) {
        if (!item) return;

        var eventName = item.event || item['1'];
        var eventData = item.ecommerce || item['2'] || item;

        log('dataLayer.push interceptado', { event: eventName, data: eventData });

        switch (eventName) {
          case 'add_to_cart':   handleAddToCart(eventData);    break;
          case 'view_item':     handleProductView(eventData);  break;
          case 'purchase':      handleOrder(eventData);        break;
          case 'view_category': handleCategoryView(eventData); break;
        }
      });

      return result;
    };

    log('dataLayer.push interceptado com sucesso', {});
  }

  function initSubscribeCheckout() {
    document.addEventListener('click', function (e) {
      var btn = e.target.closest('form.create button[type="submit"]');
      if (!btn) return;

      var form       = btn.closest('form.create');
      var email      = (form.querySelector('input[name="email"]')      || {}).value || '';
      var firstName  = (form.querySelector('input[name="first_name"]') || {}).value || '';
      var phone      = ((form.querySelector('input[name="phone"]')     || {}).value || '').replace(/\D/g, '');

      if (!email) {
        log('Subscribe Checkout | ⚠️ ABORTADO — e-mail não encontrado', {});
        return;
      }

      var payload = {
        action_type:       'subscribe',
        email:             email,
        first_name:        firstName,
        subscriber_status: '1',
        customer_tags:     'Checkout Subscribe'
      };
      if (phone) payload.phone = phone;

      dispatch(payload);
    });

    log('Subscribe Checkout | Listener registrado', {});
  }

  function initSubscribeFooter() {
    function isSubscribersUrl(url)  { return url.indexOf('/api/cms/subscribers') !== -1; }
    function isFormsProcessUrl(url) { return /\/api\/cms\/forms\/[^/]+\/process/.test(url); }

    function extractData(url, body) {
      if (isSubscribersUrl(url))  return { email: body.email,    name: body.name || '',  phone: body.phone     || '' };
      if (isFormsProcessUrl(url)) return { email: body['E-mail'], name: '',              phone: body['WhatsApp'] || '' };
      return null;
    }

    function fireSubscribe(dados) {
      if (!dados || !dados.email) return;
      dispatch({
        action_type:       'subscribe',
        email:             dados.email,
        first_name:        dados.name  || '',
        phone:             dados.phone || '',
        subscriber_status: '1',
        customer_tags:     'Newsletter Footer'
      });
    }

    var _originalFetch = window.fetch;
    window.fetch = function (url, options) {
      var result = _originalFetch.apply(this, arguments);
      try {
        var urlStr = typeof url === 'string' ? url : (url && url.url ? url.url : '');
        if ((isSubscribersUrl(urlStr) || isFormsProcessUrl(urlStr)) && options && options.body) {
          log('Subscribe Footer | [fetch] interceptado', { url: urlStr });
          var body = {};
          try { body = JSON.parse(options.body); } catch (e) {}
          var dados = extractData(urlStr, body);
          result.then(function (res) {
            if (res.ok) fireSubscribe(dados);
          });
        }
      } catch (e) {}
      return result;
    };

    var _xhrOpen = XMLHttpRequest.prototype.open;
    var _xhrSend = XMLHttpRequest.prototype.send;

    XMLHttpRequest.prototype.open = function (method, url) {
      this._edroneUrl = url || '';
      return _xhrOpen.apply(this, arguments);
    };

    XMLHttpRequest.prototype.send = function (body) {
      var xhr = this;
      if (xhr._edroneUrl && (isSubscribersUrl(xhr._edroneUrl) || isFormsProcessUrl(xhr._edroneUrl))) {
        log('Subscribe Footer | [XHR] interceptado', { url: xhr._edroneUrl });
        var xhrBody = {};
        try { xhrBody = JSON.parse(body); } catch (e) {}
        var dados = extractData(xhr._edroneUrl, xhrBody);
        xhr.addEventListener('load', function () {
          if (xhr.status >= 200 && xhr.status < 300) fireSubscribe(dados);
        });
      }
      return _xhrSend.apply(this, arguments);
    };

    log('Subscribe Footer | Interceptores registrados', {});
  }

  function findCategoryInTree(nodes, slug) {
    for (var i = 0; i < nodes.length; i++) {
      var node = nodes[i];
      var nodeSlug = node.url_key || node.slug ||
        (node.name || '').toLowerCase().replace(/[^\w]+/g, '-').replace(/^-|-$/g, '');
      if (nodeSlug === slug) return node;
      if (node.children && node.children.length) {
        var found = findCategoryInTree(node.children, slug);
        if (found) return found;
      }
    }
    return null;
  }

  function flattenCategoryTree(nodes, map, parentId) {
    map = map || {};
    (nodes || []).forEach(function (n) {
      if (n.id) map[n.id] = {
        id:        n.id.toString(),
        name:      n.name,
        parent_id: parentId ? parentId.toString() : null
      };
      if (n.childrens && n.childrens.length) flattenCategoryTree(n.childrens, map, n.id);
    });
    return map;
  }

  function buildCategoryPath(catId, map) {
    var path = [];
    var current = map[catId];
    var visited = {};

    while (current && !visited[current.id]) {
      visited[current.id] = true;
      path.unshift({ id: current.id, name: current.name });
      current = current.parent_id ? map[current.parent_id] : null;
    }

    if (!path.length) return { ids: catId.toString(), names: '' };

    return {
      ids:   path.map(function (c) { return c.id; }).join('~'),
      names: path.map(function (c) { return c.name; }).join('~')
    };
  }

  var _catMapCache = null;

  function getCategoryMap(callback) {
    if (_catMapCache) {
      return callback(_catMapCache);
    }

    var CACHE_KEY = 'edrone_cat_map';
    try {
      var cached = sessionStorage.getItem(CACHE_KEY);
      if (cached) {
        _catMapCache = JSON.parse(cached);
        log('Category Map | Do cache', { total: Object.keys(_catMapCache).length });
        return callback(_catMapCache);
      }
    } catch (e) {}

    var headers = { 'accept': 'application/json' };
    if (STORE_ID) headers['store-id'] = STORE_ID;

    fetch('/api/catalog/categories/tree?status=1', { headers: headers })
      .then(function (res) {
        if (!res.ok) throw new Error('HTTP ' + res.status);
        return res.json();
      })
      .then(function (data) {
        var tree = data.data || data.categories || (Array.isArray(data) ? data : []);
        var map  = flattenCategoryTree(tree);
        _catMapCache = map;
        try { sessionStorage.setItem(CACHE_KEY, JSON.stringify(map)); } catch (e) {}
        log('Category Map | Carregado', { total: Object.keys(map).length });
        callback(map);
      })
      .catch(function (err) {
        log('Category Map | ⚠️ Falha ao carregar árvore', { error: err.message });
        callback({});
      });
  }

  var PRODUCT_FIELDS = [
    'product_ids', 'product_skus', 'product_titles', 'product_images',
    'product_urls', 'product_counts', 'product_availability',
    'email', 'first_name', 'last_name', 'phone', 'user_id',
    'order_id', 'base_payment_value', 'order_payment_value',
    'subscriber_status', 'customer_tags'
  ];

  function waitForSDKAndFire(catId, catName) {
    try { sessionStorage.setItem('edrone_last_cat', JSON.stringify({ id: catId, name: catName })); } catch (e) {}

    getCategoryMap(function (map) {
      var path = map[catId] ? buildCategoryPath(catId, map) : { ids: catId.toString(), names: catName };
      log('Auto Category View | Hierarquia resolvida', path);

      try { sessionStorage.setItem('edrone_last_cat', JSON.stringify({ id: catId, name: catName, path: path })); } catch (e) {}

      var attempts = 0;
      var interval = setInterval(function () {
        attempts++;
        if (window._edrone && _edrone.externalLoaded && typeof _edrone.init === 'function') {
          clearInterval(interval);
          log('Auto Category View | SDK pronto, disparando', { path: path, attempts: attempts });

          PRODUCT_FIELDS.forEach(function (field) { delete _edrone[field]; });

          _edrone.action_type            = 'category_view';
          _edrone.product_category_ids   = path.ids;
          _edrone.product_category_names = encodeURIComponent(path.names);
          _edrone.init();
        } else if (attempts >= 50) {
          clearInterval(interval);
          log('Auto Category View | ⚠️ Timeout aguardando SDK', {});
        }
      }, 100);
    });
  }

  function initAutoCategoryView() {
    var path = window.location.pathname.replace(/\/$/, '') || '/';

    if (!path.match(/\/c$/)) {
      log('Auto Category View | Não é página de categoria, ignorando', { path: path });
      return;
    }

    log('Auto Category View | Página de categoria detectada', { path: path });

    var urlKey   = path.replace(/^\//, '').replace(/\/c$/, '');
    var lastSlug = urlKey.split('/').pop();

    try {
      var nuxt = window.__NUXT__ || window.__nuxt_state__;
      if (nuxt && nuxt.data && nuxt.data[0] && nuxt.data[0].category) {
        var nuxtCat = nuxt.data[0].category;
        if (nuxtCat.url_key && (nuxtCat.url_key === urlKey || nuxtCat.slug === lastSlug)) {
          log('Auto Category View | Categoria extraída do __NUXT__', { id: nuxtCat.id, name: nuxtCat.name });
          return waitForSDKAndFire(nuxtCat.id.toString(), nuxtCat.name);
        }
      }
    } catch (e) {}

    var CACHE_KEY = 'edrone_cat_' + urlKey.replace(/\//g, '_');
    var cached    = null;
    try { cached = JSON.parse(sessionStorage.getItem(CACHE_KEY)); } catch (e) {}

    if (cached) {
      log('Auto Category View | Categoria do cache', cached);
      return waitForSDKAndFire(cached.id, cached.name);
    }

    if (!STORE_ID) {
      log('Auto Category View | ⚠️ store_id não disponível, usando fallback do slug', { urlKey: urlKey });
      var catName = lastSlug.replace(/-/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); });
      return waitForSDKAndFire(lastSlug, catName);
    }

    fetch('/api/catalog/categories/url?url_key=' + encodeURIComponent(urlKey) + '&status=1', {
      headers: {
        'store-id': STORE_ID,
        'accept':   'application/json'
      }
    })
      .then(function (res) {
        if (!res.ok) throw new Error('HTTP ' + res.status);
        return res.json();
      })
      .then(function (data) {
        if (data.error || !data.data) throw new Error('Categoria não encontrada');
        var cat = data.data;
        try { sessionStorage.setItem(CACHE_KEY, JSON.stringify({ id: cat.id.toString(), name: cat.name })); } catch (e) {}
        log('Auto Category View | Categoria resolvida via API', { id: cat.id, name: cat.name });
        waitForSDKAndFire(cat.id.toString(), cat.name);
      })
      .catch(function (err) {
        log('Auto Category View | ⚠️ API falhou, usando fallback do slug', { error: err.message });
        var catNameFallback = lastSlug.replace(/-/g, ' ').replace(/\b\w/g, function (c) { return c.toUpperCase(); });
        waitForSDKAndFire(lastSlug, catNameFallback);
      });
  }

  function initAutoProductView() {
    var path = window.location.pathname.replace(/\/$/, '');

    if (!path.match(/\/p$/)) {
      log('Auto Product View | Não é página de produto, ignorando', { path: path });
      return;
    }

    log('Auto Product View | Página de produto detectada', { path: path });

    var attempts = 0;
    var interval = setInterval(function () {
      attempts++;

      try {
        var nuxt = window.__NUXT__ || window.__nuxt_state__;
        if (nuxt && nuxt.data && nuxt.data[0] && nuxt.data[0].product) {
          var p = nuxt.data[0].product;

          var urlSku  = path.replace(/\/p$/, '').split('-').pop();
          var nuxtSku = p.sku ? p.sku.toString().toLowerCase() : '';
          var nuxtSlugSku = p.slug ? p.slug.split('-').pop() : '';

          var skuMatch = (urlSku && nuxtSku && urlSku === nuxtSku) ||
                         (urlSku && nuxtSlugSku && urlSku === nuxtSlugSku);

          if (!skuMatch && p.slug) {
            if (attempts < 30) return;
          }

          clearInterval(interval);

          if (!window._edrone || !_edrone.externalLoaded) {
            if (attempts < 50) return;
            clearInterval(interval);
            log('Auto Product View | ⚠️ Timeout aguardando SDK', {});
            return;
          }

          var productId    = p.id    ? p.id.toString() : '';
          var productSku   = p.sku   || '';
          var productName  = (p.name || '').trim();
          var productImage = (p.small_image || p.thumbnail || '').split('?')[0];
          var productUrl   = window.location.href.split('?')[0];

          if (!productId) {
            log('Auto Product View | ⚠️ ABORTADO — product_id ausente', p);
            return;
          }

          setLoaderReady();

          function fireAutoWithCategories(catIds, catNames) {
            log('Auto Product View | Disparando', { id: productId, catIds: catIds });
            dispatch({
              action_type:            'product_view',
              product_ids:            productId,
              product_skus:           productSku,
              product_titles:         encodeURIComponent(productName),
              product_images:         encodeURIComponent(productImage),
              product_urls:           encodeURIComponent(productUrl),
              product_category_ids:   catIds,
              product_category_names: encodeURIComponent(catNames),
              product_availability:   p.availability || 1
            });

            var stored = lsGet('edrone_products') || [];
            if (!stored.some(function (s) { return s.product_id == productId; })) {
              stored.push({
                product_id:     productId,
                product_sku:    productSku,
                product_url:    productUrl,
                product_image:  productImage,
                category_ids:   catIds,
                category_names: catNames
              });
              lsSet('edrone_products', stored);
            }
          }

          resolveProductCategories(productId, fireAutoWithCategories);
        }
      } catch (e) {
        log('Auto Product View | ⚠️ Erro ao ler __NUXT__', { error: e.message });
      }

      if (attempts >= 50) {
        clearInterval(interval);
        log('Auto Product View | ⚠️ Timeout — __NUXT__ não disponível', {});
      }
    }, 100);
  }

  function initSPAWatcher() {
    var lastPath = window.location.pathname;

    function onRouteChange() {
      var currentPath = window.location.pathname.replace(/\/$/, '') || '/';
      if (currentPath === lastPath) return;
      lastPath = currentPath;
      log('SPA | Navegação detectada', { path: currentPath });

      if (!currentPath.match(/\/c$/)) {
        try { sessionStorage.removeItem('edrone_last_cat'); } catch (e) {}
        log('SPA | edrone_last_cat limpo (saiu de categoria)', { path: currentPath });
      }

      setTimeout(function () {
        initAutoCategoryView();
        initAutoProductView();
      }, 300);
    }

    var _originalPushState = history.pushState;
    history.pushState = function () {
      _originalPushState.apply(history, arguments);
      setTimeout(onRouteChange, 0);
    };

    var _originalReplaceState = history.replaceState;
    history.replaceState = function () {
      _originalReplaceState.apply(history, arguments);
      setTimeout(onRouteChange, 0);
    };

    window.addEventListener('popstate', function () {
      setTimeout(onRouteChange, 0);
    });

    log('SPA Watcher | Monitorando navegação', {});
  }

  loadSDK();
  interceptDataLayer();
  initSubscribeCheckout();
  initSubscribeFooter();
  initAutoCategoryView();
  initAutoProductView();
  initSPAWatcher();

  log('edrone-loader inicializado', { app_id: APP_ID, store_id: STORE_ID, debug: DEBUG });

})();
